function normalizeCustomerData(data) {
    if (Array.isArray(data)) {
        return data.map(customer => ({
            id: customer.id || customer.__ID,
            __ID: customer.id || customer.__ID,
            ...customer
        }));
    }
    return { id: data.id || data.__ID, __ID: data.id || data.__ID, ...data };
}

